mapper.select:
SELECT a.appeal_id AS appealId, a.qualitative_evaluation_id AS qualitativeEvaluationId, a.appeal_employee_id AS appealEmployeeId, e.employee_name AS employeeName, a.appeal_type AS appealType, a.title, a.status, a.review_result AS reviewResult, a.filed_at AS filedAt, a.reviewed_at AS reviewedAt FROM evaluation_appeal a JOIN employee e ON e.employee_id = a.appeal_employee_id
AND a.status = #{status}
ORDER BY a.filed_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM evaluation_appeal

    AND status = #{status}
